import{c as i,a7 as a,y as e,B as r}from"./chunks/framework.3cjvm90C.js";const b=JSON.parse('{"title":"BLIP：统一视觉语言理解与生成的预训练框架","description":"介绍 BLIP 如何通过引导式预训练统一视觉语言理解和生成任务","frontmatter":{"title":"BLIP：统一视觉语言理解与生成的预训练框架","description":"介绍 BLIP 如何通过引导式预训练统一视觉语言理解和生成任务"},"headers":[],"relativePath":"multimodal/blip.md","filePath":"multimodal/blip.md","lastUpdated":1782456021000}'),n={name:"multimodal/blip.md"};function t(o,l,p,s,h,d){return a(),e("div",null,[...l[0]||(l[0]=[r('<h1 id="blip-引导语言图像预训练-实现统一的视觉语言理解和生成" tabindex="-1">BLIP：引导语言图像预训练，实现统一的视觉语言理解和生成 <a class="header-anchor" href="#blip-引导语言图像预训练-实现统一的视觉语言理解和生成" aria-label="Permalink to “BLIP：引导语言图像预训练，实现统一的视觉语言理解和生成”">​</a></h1><p>BLIP 是一种用于统一视觉语言理解和生成的新预训练框架，它在各种视觉语言任务上取得了最先进的结果。</p><hr><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to “背景”">​</a></h2><p>视觉和语言是人类感知世界的两种最基本的方式，也是人工智能的两大关键基石。人工智能的一个长期目标是构建能够通过视觉和语言输入理解世界并通过自然语言与人类交流的智能代理。</p><p>为了实现这一目标，视觉语言预训练 已成为一种有效的方法，其中深度神经网络模型在大规模图像文本数据集上进行预训练，以提高下游视觉语言任务（例如图像文本）的性能。文本检索、图像字幕和视觉问答。</p><p>简而言之，视觉语言预训练旨在利用图像文本数据来教会模型共同理解视觉和文本信息的能力。通过预训练，模型在微调之前就已经过训练（微调涉及使用下游任务的数据对预训练模型进行额外的训练）。如果没有预训练，模型需要在每个下游任务上从头开始训练，这会导致性能下降。</p><h2 id="局限-大多数模型缺乏灵活性-web-数据嘈杂" tabindex="-1">局限：大多数模型缺乏灵活性，Web 数据嘈杂 <a class="header-anchor" href="#局限-大多数模型缺乏灵活性-web-数据嘈杂" aria-label="Permalink to “局限：大多数模型缺乏灵活性，Web 数据嘈杂”">​</a></h2><p>尽管视觉语言预训练取得了巨大成功，但现有方法有两个主要局限性：</p><ul><li><p>从模型角度来看，大多数现有的预训练模型不够灵活，无法适应广泛的视觉语言任务。基于编码器的模型不太容易直接转移到文本生成任务，而编码器-解码器模型尚未成功应用于图像文本检索任务。</p></li><li><p>从数据角度来看，大多数模型都会对从网络自动收集的图像和替代文本对进行预训练。然而，网络文本通常不能准确描述图像的视觉内容，使它们成为监督的嘈杂来源。</p></li></ul><h2 id="我们的解决方案-用-blip-翻转剧本" tabindex="-1">我们的解决方案：用 BLIP 翻转剧本 <a class="header-anchor" href="#我们的解决方案-用-blip-翻转剧本" aria-label="Permalink to “我们的解决方案：用 BLIP 翻转剧本”">​</a></h2><p>为了解决这些限制，我们提出了 BLIP：Bootstrapping Language-Image Pre-training（语言-图像预训练），以实现视觉-语言的统一理解和生成。BLIP 介绍：</p><ul><li>一种新的模型架构，能够比现有方法实现更广泛的下游任务；</li><li>一种新的数据集引导方法，用于从嘈杂的网络数据中学习。</li></ul><p>BLIP 在七项视觉语言任务上实现了最先进的性能，包括：</p><ul><li>image-text retrieval</li><li>image captioning</li><li>visual question answering</li><li>visual reasoning</li><li>visual dialog</li><li>zero-shot text-video retrieval</li><li>zero-shot video question answering.</li></ul><h2 id="深入探讨-blip-的工作原理" tabindex="-1">深入探讨： BLIP 的工作原理 <a class="header-anchor" href="#深入探讨-blip-的工作原理" aria-label="Permalink to “深入探讨： BLIP 的工作原理”">​</a></h2><p>视觉语言理解和生成的统一模型</p><p>为了预训练具有理解和生成能力的统一视觉语言模型， BLIP 引入了编码器-解码器的多模态混合模型，这是一个多任务模型，可在三种功能之一中运行：</p><ol><li>单模态编码器，分别对图像和文本进行编码。图像编码器是一个视觉变换器。文本编码器与 BERT 相同。文本输入的开头会添加一个 [CLS] 标记，用于总结句子。</li><li>基于图像的文本编码器，通过在文本编码器的每个变换器块的自注意力层和前馈网络之间插入交叉注意力层来注入视觉信息。特定于任务的 [Encode] 标记被附加到文本中，并且 [Encode] 的输出嵌入用作图像-文本对的多模态表示。</li><li>基于图像的文本解码器，用因果自注意力层替换文本编码器中的双向自注意力层。特殊的 [Decode] 标记用于表示序列的开始。</li></ol><p>BLIP 在预训练过程中联合优化了三个目标，其中两个基于理解的目标（ITC、ITM）和一个基于生成的目标（LM）：</p><ul><li>图像文本对比损失（ITC）激活单模态编码器。它的目的是对齐视觉变换器和文本变换器的特征空间，通过鼓励正图像-文本对与负图像-文本对相比具有更为相似的表示。</li><li>图像文本匹配损失（ITM）激活基于图像的文本编码器。ITM 是一项二元分类任务，要求模型在给定多模态特征的情况下预测图像-文本对是正（匹配）还是负（不匹配）。</li><li>语言建模损失（LM）激活基于图像的文本解码器，其目的是生成以图像为条件的文本描述。</li></ul><p>在不同的下游任务中，我们微调预训练模型的不同路径以实现不同的目标，如下面的动画所示。</p><h2 id="从嘈杂的图像文本对中引导字幕" tabindex="-1">从嘈杂的图像文本对中引导字幕 <a class="header-anchor" href="#从嘈杂的图像文本对中引导字幕" aria-label="Permalink to “从嘈杂的图像文本对中引导字幕”">​</a></h2><p>视觉语言预训练依赖于从网络自动收集的大规模图像文本对。然而，文本通常不能准确地描述图像的视觉内容，这使得它们成为一种嘈杂的监督。</p><p>为了解决这个问题，我们通过引入两个模块来引导字幕：字幕生成器和过滤器。</p><ul><li>字幕生成器是一个基于图像的文本解码器。给定网络图像，我们使用字幕生成器生成合成字幕作为额外的训练样本。</li><li>过滤器是一个基于图像的文本编码器。它会删除与相应图像不匹配的嘈杂字幕。</li></ul><h2 id="结果" tabindex="-1">结果 <a class="header-anchor" href="#结果" aria-label="Permalink to “结果”">​</a></h2><p>通过引导数据集，我们的预训练模型在下游任务上实现了显着的性能改进，如下表所示。</p><p>我们还发现，由于合成字幕的多样性更高，因此使用随机解码方法（核采样）比使用波束搜索来生成字幕更好。</p><p>下面我们展示了 BLIP 在图像文本检索上的性能，在使用相同数量的图像的情况下，它的平均召回率 @1 比现有最先进的<a href="https://arxiv.org/abs/2107.07651?ref=blog.salesforceairesearch.com" target="_blank" rel="noreferrer">ALBEF</a>高出 2.7% 。（有关其他任务的更多结果，请参阅我们的<a href="https://arxiv.org/abs/2201.12086?ref=blog.salesforceairesearch.com" target="_blank" rel="noreferrer">论文</a>）</p><hr><h2 id="影响" tabindex="-1">影响 <a class="header-anchor" href="#影响" aria-label="Permalink to “影响”">​</a></h2><p>BLIP 研究对人工智能及其他领域有好处：</p><ul><li>AI 优势</li></ul><p>： BLIP 对人工智能的贡献包括：</p><ul><li><p>为统一的基于图像的文本理解和生成任务生成最先进的视觉语言预训练模型</p></li><li><p>引入了从嘈杂的网络数据中学习的新框架</p></li><li><p>通过以下方式处理噪音：</p></li><li><p>生成合成字幕作为额外的训练样本</p></li><li><p>删除嘈杂的字幕</p></li><li><p>更广泛（一般）影响： BLIP 可以通过更好的视觉语言智能来实现广泛的下游应用，例如电子商务平台中的产品推荐和分类。</p></li></ul><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to “总结”">​</a></h2><ul><li>视觉语言研究是：</li><li>人工智能的核心问题，因为视觉和语言是世界上两种基本的信息模态</li><li>这是一个重要的应用领域，因为许多工业人工智能应用都是由视觉语言智能提供支持的。</li><li>我们的框架称为 BLIP，它介绍了：</li><li>一种新的模型架构，能够比现有方法实现更广泛的下游任务</li><li>一种新的数据集引导方法，用于从嘈杂的网络数据中学习。</li><li>BLIP 框架为深度学习和人工智能做出了宝贵的贡献：</li><li>为统一的基于图像的文本理解和生成任务生成最先进的视觉语言预训练模型</li><li>BLIP 用于从嘈杂的网络数据中学习的新框架很有价值，因为网络收集的图像描述通常不准确，即充满噪音。</li><li>提供简单、灵活且强大的视觉语言模型，可以进行端到端微调</li><li>我们微调预训练模型的不同路径，以在不同的下游任务上实现不同的目标</li><li>在图像文本检索、图像字幕、视觉问答、视觉推理和视觉对话方面实现最先进的性能。</li><li>以零样本方式直接转移到视频语言任务时表现出很强的泛化能力。</li><li>BLIP 还提供更广泛的好处：</li><li>为广泛的下游应用提供更好的视觉语言智能，例如电子商务平台中的产品推荐和分类。</li><li>演示示例显示 BLIP 可以：</li><li>生成准确详细的图像标题</li><li>为一系列不同的问题生成准确的答案。</li><li>我们发布了代码、模型和引导数据集，以促进视觉语言研究和工业应用。</li></ul><h2 id="相关资源" tabindex="-1">相关资源 <a class="header-anchor" href="#相关资源" aria-label="Permalink to “相关资源”">​</a></h2><ul><li>ALBEF (ALign BEfore Fuse):</li><li>Blog post:</li><li><a href="https://blog.salesforceairesearch.com/align-before-fuse/" target="_blank" rel="noreferrer">Align before Fuse (ALBEF): Advancing Vision-language Understanding with Contrastive Learning</a></li><li>Research paper:</li><li><a href="https://arxiv.org/abs/2107.07651?ref=blog.salesforceairesearch.com" target="_blank" rel="noreferrer">Align before Fuse: Vision and Language Representation Learning with Momentum Distillation</a>, Advances in Neural Information Processing Systems (Spotlight), 2021.</li></ul><h2 id="附录-术语和定义" tabindex="-1">附录：术语和定义 <a class="header-anchor" href="#附录-术语和定义" aria-label="Permalink to “附录：术语和定义”">​</a></h2><p>对我们讨论中使用的一些人工智能/深度学习术语的回顾：</p><ul><li>图像文本数据集：数据的集合，其中每一项都是图像文本对，即一个或多个图像加上一个或多个文本描述的组合</li><li>预训练：模型在适应（或微调）下游任务数据之前已经过训练</li><li>微调：使用目标任务的数据进一步训练预训练模型</li><li>端到端：模型的所有参数都可以联合训练</li><li>编码器视觉语言模型：一种将图像文本数据编码为特征表示的模型，通常用于执行基于理解的任务</li><li>Encoder-Decoder 视觉语言模型：一种首先将图像文本编码为多模态特征，然后将特征解码为文本的模型</li><li>数据集引导：一种生成额外（合成）数据供系统用于构建模型的方法。</li></ul>',43)])])}const u=i(n,[["render",t]]);export{b as __pageData,u as default};
